import{_ as a,o as e,c as i,a2 as r}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"挂牌查价","description":"","frontmatter":{},"headers":[],"relativePath":"projects/lansi/listing-price-check.md","filePath":"projects/lansi/listing-price-check.md"}'),l={name:"projects/lansi/listing-price-check.md"};function s(o,t,n,d,c,h){return e(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="挂牌查价" tabindex="-1">挂牌查价 <a class="header-anchor" href="#挂牌查价" aria-label="Permalink to &quot;挂牌查价&quot;">​</a></h1><blockquote><p>挂牌查价是在 2021 年上海二手房核验价政策密集出台阶段快速上线的轻量查询工具。它把 <span class="text-highlight-blue">二手房核验价、挂牌价和楼盘成交参考</span> 组织成可搜索、可订阅、可提醒的高频查询产品，阶段性获得 2 万+ 用户。</p></blockquote><div class="project-snapshot"><div><strong>2 万+</strong><span>2021 年 7-8 月政策窗口期快速获得用户</span></div><div><strong>快速上线</strong><span>结合政策热点与用户需求，短周期完成产品化</span></div><div><strong>订阅提醒</strong><span>支持楼盘订阅、价格变动提醒和私域转化路径</span></div><div><strong>新房互补</strong><span>与一房一万新房形成新房 / 二手房双线覆盖</span></div></div><h2 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h2><p>2021 年上海二手房核验价政策密集出台，用户对&quot;我关注的楼盘核验价是多少&quot;&quot;价格有没有变化&quot;有强烈的查询需求。传统平台信息繁杂，用户需要一个快速搜索、持续关注、及时提醒的轻量工具。</p><p>挂牌查价要解决的核心问题：把二手房价格信息从&quot;要找才能看到&quot;变成&quot;订阅就能收到&quot;，结合政策窗口期快速承接高频用户需求。</p><h2 id="项目目标" tabindex="-1">项目目标 <a class="header-anchor" href="#项目目标" aria-label="Permalink to &quot;项目目标&quot;">​</a></h2><ul><li>提供高频、轻量的二手房核验价与挂牌价查询服务。</li><li>支持楼盘搜索、价格展示、订阅提醒和私域转化。</li><li>快速响应政策热点，抓住用户集中关注的时间窗口。</li><li>与一房一万新房形成新房 / 二手房场景互补。</li></ul><h2 id="我的角色" tabindex="-1">我的角色 <a class="header-anchor" href="#我的角色" aria-label="Permalink to &quot;我的角色&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工作方向</th><th>我承担的工作</th></tr></thead><tbody><tr><td>产品结构</td><td>设计楼盘搜索、价格展示、订阅、提醒和私域转化路径</td></tr><tr><td>数据口径</td><td>梳理核验价、挂牌价、成交参考等价格字段和展示逻辑</td></tr><tr><td>版本迭代</td><td>根据用户行为和政策变化持续优化查询体验</td></tr><tr><td>数据分析</td><td>用搜索热度、订阅量和访问趋势判断产品价值和迭代方向</td></tr></tbody></table><h2 id="数据如何驱动" tabindex="-1">数据如何驱动 <a class="header-anchor" href="#数据如何驱动" aria-label="Permalink to &quot;数据如何驱动&quot;">​</a></h2><ul><li>价格数据提供用户查询的核心价值。</li><li>搜索和订阅数据反映用户关注楼盘和区域。</li><li>访问趋势反映政策热点和市场关注变化。</li><li>私域转化数据帮助判断工具型产品的商业价值。</li></ul><h2 id="成果" tabindex="-1">成果 <a class="header-anchor" href="#成果" aria-label="Permalink to &quot;成果&quot;">​</a></h2><div class="insight-card"><span class="label">项目结果</span><p>2021 年 7-8 月政策窗口期，挂牌查价快速获得 2 万+ 用户，以轻量工具形态承接政策热点和高频查询需求，沉淀了热点业务快速上线和数据工具产品化经验。</p></div>',14)])])}const q=a(l,[["render",s]]);export{u as __pageData,q as default};
